1	/**
2	 * The Spider — public types.
3	 *
4	 * Rig and engine data model, CrawlResult, SpiderApi, and configuration.
5	 * Engine yield shapes (DraftYields, SealYields) live here too so downstream
6	 * packages can import them without depending on the engine implementation files.
7	 */
8	
9	import type { ZodSchema } from 'zod';
10	
11	// ── Engine instance status ────────────────────────────────────────────
12	
13	export type EngineStatus = 'pending' | 'running' | 'completed' | 'failed' | 'cancelled' | 'blocked' | 'skipped';
14	
15	// ── Block record ──────────────────────────────────────────────────────
16	
17	/**
18	 * Persisted record of an active engine block.
19	 * Present on an EngineInstance when status === 'blocked'.
20	 * Cleared when the block is resolved.
21	 */
22	export interface BlockRecord {
23	  /** Block type identifier (matches a registered BlockType.id). */
24	  type: string;
25	  /** Structured condition payload — shape validated by the block type's conditionSchema. */
26	  condition: unknown;
27	  /** ISO timestamp when the engine was blocked. */
28	  blockedAt: string;
29	  /** Optional human-readable message from the engine. */
30	  message?: string;
31	  /** ISO timestamp of the last checker evaluation. Updated on every check cycle. */
32	  lastCheckedAt?: string;
33	}
34	
35	// ── Engine instance ───────────────────────────────────────────────────
36	
37	/**
38	 * A single engine slot within a rig.
39	 *
40	 * `id` is the engine's position identifier (e.g. 'draft', 'implement').
41	 * For the static pipeline it matches `designId`.
42	 *
43	 * `givensSpec` holds values set at spawn time (writ, role, commands) and
44	 * may contain unresolved yield expression strings (`${yields.<id>.<path>}`)
45	 * that the Spider resolves at run time from upstream engine yields.
46	 */
47	export interface EngineInstance {
48	  /** Unique identifier within the rig (e.g. 'draft', 'implement'). */
49	  id: string;
50	  /** The engine design to look up in the Fabricator. */
51	  designId: string;
52	  /** Current execution status. */
53	  status: EngineStatus;
54	  /** Engine IDs that must be completed before this engine can run. */
55	  upstream: string[];
56	  /**
57	   * Givens values. Spawn-time expressions (`${writ}`, `${writ.*}`, `${vars.*}`)
58	   * are resolved to their values. Yield expressions (`${yields.*}`) remain as
59	   * literal `${yields.*}` strings and are resolved at run time when the engine
60	   * is executed.
61	   */
62	  givensSpec: Record<string, unknown>;
63	  /**
64	   * Conditional activation expression, copied from the template.
65	   * Evaluated at runtime when upstream is all done. Absent means unconditional.
66	   */
67	  when?: string;
68	  /** Yields from a completed engine run (JSON-serializable). */
69	  yields?: unknown;
70	  /** Error message if this engine failed. */
71	  error?: string;
72	  /** Session ID from a launched quick engine, used by the collect step. */
73	  sessionId?: string;
74	  /** ISO timestamp when execution started. */
75	  startedAt?: string;
76	  /** ISO timestamp when execution completed (or failed). */
77	  completedAt?: string;
78	  /** Present when status === 'blocked'. Cleared when the block is resolved. */
79	  block?: BlockRecord;
80	}
81	
82	// ── Rig ──────────────────────────────────────────────────────────────
83	
84	export type RigStatus = 'running' | 'completed' | 'failed' | 'blocked';
85	
86	/**
87	 * A rig — the execution context for a single writ.
88	 *
89	 * Stored in The Stacks (`spider/rigs` book). The `engines` array is the
90	 * ordered pipeline of engine instances. The Spider updates this document
91	 * in-place as engines run and complete.
92	 */
93	export interface RigDoc {
94	  /** Index signature required to satisfy BookEntry constraint. */
95	  [key: string]: unknown;
96	  /** Unique rig id. */
97	  id: string;
98	  /** The writ this rig is executing. */
99	  writId: string;
100	  /** Current rig status. */
101	  status: RigStatus;
102	  /** Ordered engine pipeline. */
103	  engines: EngineInstance[];
104	  /** ISO timestamp when the rig was created. */
105	  createdAt: string;
106	  /** Engine id whose yields provide the resolution summary. Set at spawn time. */
107	  resolutionEngineId?: string;
108	}
109	
110	// ── Rig filters ───────────────────────────────────────────────────────
111	
112	/**
113	 * Filters for listing rigs.
114	 */
115	export interface RigFilters {
116	  /** Filter by rig status. */
117	  status?: RigStatus;
118	  /** Maximum number of results (default: 20). */
119	  limit?: number;
120	  /** Number of results to skip. */
121	  offset?: number;
122	}
123	
124	// ── Rig templates ─────────────────────────────────────────────────────
125	
126	/**
127	 * A single engine slot declared in a rig template.
128	 */
129	export interface RigTemplateEngine {
130	  /** Engine id unique within this template. */
131	  id: string;
132	  /** Engine design id to look up in the Fabricator. */
133	  designId: string;
134	  /** Engine ids within this template whose completion is required first. Defaults to []. */
135	  upstream?: string[];
136	  /**
137	   * Givens to pass to the engine.
138	   *
139	   * String values may contain `${...}` template expressions:
140	   *   `${writ}` — the full WritDoc for this rig's writ
141	   *   `${writ.<path>}` — a field of the WritDoc (dot-path traversal)
142	   *   `${vars.<path>}` — value from spider.variables config (dot-path traversal)
143	   *   `${yields.<engine_id>.<path>}` — a property from an upstream engine's
144	   *       yields (resolved at run time, dot-path traversal)
145	   *
146	   * When a string is exactly one expression (e.g. `${writ}`), the resolved
147	   * value preserves its original type. When expressions are embedded in a
148	   * larger string, the result is always a string.
149	   *
150	   * Non-string values are passed through literally.
151	   * Whole-value expressions that resolve to undefined cause the key to be omitted.
152	   * Inline expressions that resolve to undefined are replaced with empty string.
153	   *
154	   * Use `\${` to produce a literal `${` in the output without interpolation.
155	   */
156	  givens?: Record<string, unknown>;
157	  /**
158	   * Conditional activation expression. A `${yields.<engine_id>.<property>}` reference
159	   * (with optional `!` negation prefix) evaluated at runtime when the engine's upstream
160	   * is all done. When the condition is falsy, the engine is set to `skipped` status.
161	   * When absent, the engine is unconditional (always runs).
162	   *
163	   * Examples:
164	   *   '${yields.review.passed}'  — run this engine when review.passed is truthy
165	   *   '!${yields.review.passed}' — run this engine when review.passed is falsy
166	   */
167	  when?: string;
168	}
169	
170	/**
171	 * A complete rig template.
172	 */
173	export interface RigTemplate {
174	  /** Ordered list of engine slot declarations. */
175	  engines: RigTemplateEngine[];
176	  /**
177	   * Engine id whose yields provide the writ resolution summary.
178	   * Falls back to seal engine, then last completed engine in array order.
179	   */
180	  resolutionEngine?: string;
181	}
182	
183	// ── CrawlResult ────────────────────────────────────────────────────────
184	
185	/**
186	 * The result of a single crawl() call.
187	 *
188	 * Variants, ordered by priority:
189	 * - 'engine-completed'  — an engine finished (collected or ran inline); rig still running
190	 * - 'engine-started'    — launched a quick engine's session
191	 * - 'engine-blocked'    — engine entered blocked status; rig is still running (other engines active)
192	 * - 'engine-unblocked'  — a blocked engine's condition cleared; engine returned to pending
193	 * - 'rig-spawned'       — created a new rig for a ready writ
194	 * - 'rig-completed'     — the crawl step caused a rig to reach a terminal state
195	 * - 'rig-blocked'       — all forward progress stalled; rig entered blocked status
196	 *
197	 * null means no work was available.
198	 */
199	export type CrawlResult =
200	  | { action: 'engine-completed'; rigId: string; engineId: string }
201	  | { action: 'engine-started'; rigId: string; engineId: string }
202	  | { action: 'engine-blocked'; rigId: string; engineId: string; blockType: string }
203	  | { action: 'engine-unblocked'; rigId: string; engineId: string }
204	  | { action: 'engine-skipped'; rigId: string; engineId: string; cascadeSkipped?: string[] }
205	  | { action: 'engine-grafted'; rigId: string; engineId: string; graftedEngineIds: string[] }
206	  | { action: 'rig-spawned'; rigId: string; writId: string }
207	  | { action: 'rig-completed'; rigId: string; writId: string; outcome: 'completed' | 'failed' }
208	  | { action: 'rig-blocked'; rigId: string; writId: string };
209	
210	// ── Block type ────────────────────────────────────────────────────────
211	
212	/**
213	 * Result of a block type check.
214	 *
215	 * 'cleared' — condition met, unblock the engine.
216	 * 'pending' — condition not yet met, keep polling.
217	 * 'failed'  — condition is permanently unresolvable, fail the engine.
218	 *
219	 * When status is 'failed', an optional reason provides a human-readable
220	 * explanation that the Spider includes in the engine error message.
221	 */
222	export interface CheckResult {
223	  status: 'cleared' | 'pending' | 'failed';
224	  reason?: string;
225	}
226	
227	/** Summary info for a registered block type. */
228	export interface BlockTypeInfo {
229	  /** Block type id. */
230	  id: string;
231	  /** Plugin id that contributed this block type. */
232	  pluginId: string;
233	  /** Suggested poll interval in milliseconds, if set. */
234	  pollIntervalMs?: number;
235	}
236	
237	/** Summary info for a registered rig template. */
238	export interface RigTemplateInfo {
239	  /** Template name (plain for config, qualified pluginId.name for kit). */
240	  name: string;
241	  /** 'config' for guild.json templates, or the pluginId for kit-contributed templates. */
242	  source: string;
243	  /** The template definition. */
244	  template: RigTemplate;
245	}
246	
247	/**
248	 * A registered block type — defines how to check whether a blocking
249	 * condition has cleared. Contributed via kit/supportKit `blockTypes`.
250	 */
251	export interface BlockType {
252	  /** Unique identifier (e.g. 'writ-status', 'scheduled-time'). */
253	  id: string;
254	  /**
255	   * Check whether the blocking condition has been resolved.
256	   *
257	   * Return { status: 'cleared' } when the condition is met.
258	   * Return { status: 'pending' } when the condition is not yet met.
259	   * Return { status: 'failed' } or { status: 'failed', reason: '...' }
260	   * when the condition is permanently unresolvable.
261	   *
262	   * Throwing is reserved for transient errors (network failures, etc.)
263	   * — the engine stays blocked and the checker is retried next cycle.
264	   */
265	  check: (condition: unknown) => Promise<CheckResult>;
266	  /** Zod schema for validating the condition payload at block time. */
267	  conditionSchema: ZodSchema;
268	  /** Suggested poll interval in milliseconds. If absent, check every crawl cycle. */
269	  pollIntervalMs?: number;
270	}
271	
272	// ── SpiderApi ─────────────────────────────────────────────────────────
273	
274	/**
275	 * The Spider's public API — retrieved via guild().apparatus<SpiderApi>('spider').
276	 */
277	export interface SpiderApi {
278	  /**
279	   * Execute one step of the crawl loop.
280	   *
281	   * Priority ordering: collect > checkBlocked > run > spawn.
282	   * Returns null when no work is available.
283	   */
284	  crawl(): Promise<CrawlResult | null>;
285	
286	  /**
287	   * Show a rig by id. Throws if not found.
288	   */
289	  show(id: string): Promise<RigDoc>;
290	
291	  /**
292	   * List rigs with optional filters, ordered by createdAt descending.
293	   */
294	  list(filters?: RigFilters): Promise<RigDoc[]>;
295	
296	  /**
297	   * Find the rig for a given writ. Returns null if no rig exists.
298	   */
299	  forWrit(writId: string): Promise<RigDoc | null>;
300	
301	  /**
302	   * Manually clear a block on a specific engine, regardless of checker result.
303	   * Throws if the engine is not blocked.
304	   */
305	  resume(rigId: string, engineId: string): Promise<void>;
306	
307	  /**
308	   * Look up a registered block type by ID.
309	   */
310	  getBlockType(id: string): BlockType | undefined;
311	
312	  /**
313	   * List all registered block types with summary info.
314	   */
315	  listBlockTypes(): BlockTypeInfo[];
316	
317	  /**
318	   * List all registered rig templates with provenance info.
319	   */
320	  listTemplates(): RigTemplateInfo[];
321	
322	  /**
323	   * Return the merged effective writ-type → template-name mapping.
324	   * Config mappings override kit mappings for the same writ type.
325	   */
326	  listTemplateMappings(): Record<string, string>;
327	}
328	
329	// ── Configuration ─────────────────────────────────────────────────────
330	
331	/**
332	 * Spider apparatus configuration — lives under the `spider` key in guild.json.
333	 */
334	export interface SpiderConfig {
335	  /**
336	   * Polling interval for crawlContinual tool (milliseconds).
337	   * Default: 5000.
338	   */
339	  pollIntervalMs?: number;
340	  /**
341	   * Build command to pass to quick engines.
342	   */
343	  buildCommand?: string;
344	  /**
345	   * Test command to pass to quick engines.
346	   */
347	  testCommand?: string;
348	  /**
349	   * Named rig templates. Keys are template names (not writ types).
350	   * Templates are looked up by name via rigTemplateMappings.
351	   * A template named 'default' is used as the fallback when no mapping matches.
352	   */
353	  rigTemplates?: Record<string, RigTemplate>;
354	  /**
355	   * Writ type → rig template name mappings.
356	   * 'default' key is the fallback for unmatched writ types.
357	   * Config mappings override kit-contributed mappings for the same writ type.
358	   */
359	  rigTemplateMappings?: Record<string, string>;
360	  /**
361	   * User-defined variables available in rig template givens via `${vars.<path>}`.
362	   * Values are passed through literally (string, number, boolean, object).
363	   * Variables resolving to undefined (key absent) cause the givens key to be omitted.
364	   */
365	  variables?: Record<string, unknown>;
366	  /**
367	   * Maximum number of engines allowed in a single rig.
368	   * Grafts that would exceed this limit fail the originating engine.
369	   * Default: 50.
370	   */
371	  maxEnginesPerRig?: number;
372	}
373	
374	// ── Engine yield shapes ───────────────────────────────────────────────
375	
376	/**
377	 * Yields from the `draft` clockwork engine.
378	 * The Spider stores these in the engine instance and passes them
379	 * to downstream engines via context.upstream['draft'].
380	 */
381	export interface DraftYields {
382	  /** The draft's unique id. */
383	  draftId: string;
384	  /** Codex this draft belongs to. */
385	  codexName: string;
386	  /** Git branch name for the draft. */
387	  branch: string;
388	  /** Absolute filesystem path to the draft's worktree. */
389	  path: string;
390	  /** HEAD commit SHA at the time the draft was opened. Used by review engine to compute diffs. */
391	  baseSha: string;
392	}
393	
394	/**
395	 * Yields from the `seal` clockwork engine.
396	 */
397	export interface SealYields {
398	  /** The commit SHA at head of the target branch after sealing. */
399	  sealedCommit: string;
400	  /** Git strategy used. */
401	  strategy: 'fast-forward' | 'rebase';
402	  /** Number of retry attempts. */
403	  retries: number;
404	  /** Number of inscriptions (commits) sealed. */
405	  inscriptionsSealed: number;
406	}
407	
408	/**
409	 * Yields from the `implement` quick engine.
410	 * Set by the Spider's collect step when the Animator session completes.
411	 */
412	export interface ImplementYields {
413	  /** The Animator session id. */
414	  sessionId: string;
415	  /** Terminal status of the session. */
416	  sessionStatus: 'completed' | 'failed';
417	}
418	
419	/**
420	 * A single mechanical check (build or test) run by the review engine
421	 * before launching the reviewer session.
422	 */
423	export interface MechanicalCheck {
424	  /** Check name. */
425	  name: 'build' | 'test';
426	  /** Whether the command exited with code 0. */
427	  passed: boolean;
428	  /** Combined stdout+stderr, truncated to 4KB. */
429	  output: string;
430	  /** Wall-clock duration of the check in milliseconds. */
431	  durationMs: number;
432	}
433	
434	/**
435	 * Yields from the `review` quick engine.
436	 * Assembled by the Spider's collect step from session.output and session.metadata.
437	 */
438	export interface ReviewYields {
439	  /** The Animator session id. */
440	  sessionId: string;
441	  /** Reviewer's overall assessment — true if the review passed. */
442	  passed: boolean;
443	  /** Structured markdown findings from the reviewer's final message. */
444	  findings: string;
445	  /** Mechanical check results run before the reviewer session. */
446	  mechanicalChecks: MechanicalCheck[];
447	}
448	
449	/**
450	 * Yields from the `revise` quick engine.
451	 * Set by the Spider's collect step when the Animator session completes.
452	 */
453	export interface ReviseYields {
454	  /** The Animator session id. */
455	  sessionId: string;
456	  /** Terminal status of the session. */
457	  sessionStatus: 'completed' | 'failed';
458	}
459	
460	// ── Input request types ──────────────────────────────────────────────
461	
462	export type InputRequestStatus = 'pending' | 'completed' | 'rejected';
463	
464	export interface ChoiceQuestionSpec {
465	  type: 'choice';
466	  /** Human-readable question text. */
467	  label: string;
468	  /** Optional long-form context, explanation, or instructions for this question. */
469	  details?: string;
470	  /** Key → display label options map. */
471	  options: Record<string, string>;
472	  /** When true, the patron can supply a freeform answer instead of selecting. */
473	  allowCustom: boolean;
474	}
475	
476	export interface BooleanQuestionSpec {
477	  type: 'boolean';
478	  /** Human-readable question text. */
479	  label: string;
480	  /** Optional long-form context, explanation, or instructions for this question. */
481	  details?: string;
482	}
483	
484	export interface TextQuestionSpec {
485	  type: 'text';
486	  /** Human-readable question text. */
487	  label: string;
488	  /** Optional long-form context, explanation, or instructions for this question. */
489	  details?: string;
490	}
491	
492	export type QuestionSpec = ChoiceQuestionSpec | BooleanQuestionSpec | TextQuestionSpec;
493	
494	/** Discriminated choice answer — selected from options or freeform custom. */
495	export type ChoiceAnswer = { selected: string } | { custom: string };
496	
497	/**
498	 * Answer value union. Runtime type is determined by the corresponding QuestionSpec:
499	 * - choice → ChoiceAnswer (object with 'selected' or 'custom' key)
500	 * - boolean → boolean
501	 * - text → string
502	 */
503	export type AnswerValue = ChoiceAnswer | boolean | string;
504	
505	/**
506	 * An input request document stored in the spider/input-requests book.
507	 * Created by engines before blocking; answered by patrons via CLI tools.
508	 */
509	export interface InputRequestDoc {
510	  [key: string]: unknown;
511	  /** Unique ID via generateId('ir', 4). */
512	  id: string;
513	  /** Rig this request belongs to. */
514	  rigId: string;
515	  /** Engine that created this request. */
516	  engineId: string;
517	  /** Request lifecycle status. */
518	  status: InputRequestStatus;
519	  /** Optional human-readable context from the engine. */
520	  message?: string;
521	  /** Question key → question spec. */
522	  questions: Record<string, QuestionSpec>;
523	  /** Question key → answer value. Partially filled until completion. */
524	  answers: Record<string, AnswerValue>;
525	  /** Set when status transitions to 'rejected'. */
526	  rejectionReason?: string;
527	  /** ISO timestamp when the request was created. */
528	  createdAt: string;
529	  /** ISO timestamp of the last mutation. */
530	  updatedAt: string;
531	}
532	
533	// ── Spider-extended engine run / collect result types ─────────────────
534	
535	/**
536	 * Spider-extended engine run result. Adds an optional `graft` field
537	 * to the `completed` variant, allowing engines to dynamically append
538	 * new engines to the rig alongside their yields.
539	 *
540	 * Engines that want to graft import this type from @shardworks/spider-apparatus.
541	 * Engines that don't graft use the base EngineRunResult from @shardworks/fabricator-apparatus.
542	 *
543	 * The Spider internally checks for the `graft` property on any completed result
544	 * (duck-typing — the Fabricator type is not modified).
545	 */
546	export type SpiderEngineRunResult =
547	  | { status: 'completed'; yields: unknown; graft?: RigTemplateEngine[] }
548	  | { status: 'launched'; sessionId: string }
549	  | { status: 'blocked'; blockType: string; condition: unknown; message?: string };
