551	/**
552	 * Spider-extended collect result. When a quick engine's collect() method
553	 * returns an object with a `graft` property (an array), the Spider extracts
554	 * it as a graft request and uses the `yields` property as the engine's yields.
555	 *
556	 * When collect() returns a value without a `graft` array property, the entire
557	 * return value is treated as yields (backward compatible).
558	 */
559	export interface SpiderCollectResult {
560	  yields: unknown;
561	  graft?: RigTemplateEngine[];
562	}
