2	 * Anima-session engine — quick (Animator-backed).
3	 *
4	 * A generic reusable engine that summons an anima session. Unlike the other
5	 * quick engines which embed prompt logic, anima-session receives all parameters
6	 * through givens: role, prompt, cwd, and optionally conversationId and writ.
7	 *
8	 * Returns `{ status: 'launched', sessionId }` so the Spider's collect step
9	 * can poll for completion on subsequent walks. Uses the generic default
10	 * collect — no custom collect method.
11	 */
12	
13	import { guild } from '@shardworks/nexus-core';
14	import type { EngineDesign } from '@shardworks/fabricator-apparatus';
15	import type { AnimatorApi } from '@shardworks/animator-apparatus';
16	import type { WritDoc } from '@shardworks/clerk-apparatus';
17	
18	const animaSessionEngine: EngineDesign = {
19	  id: 'anima-session',
20	
21	  async run(givens, context) {
22	    // Validate required givens
23	    if (typeof givens.role !== 'string' || givens.role.length === 0) {
24	      throw new Error('anima-session engine requires a non-empty string "role" given.');
25	    }
26	    if (typeof givens.prompt !== 'string' || givens.prompt.length === 0) {
27	      throw new Error('anima-session engine requires a non-empty string "prompt" given.');
28	    }
29	    if (typeof givens.cwd !== 'string' || givens.cwd.length === 0) {
30	      throw new Error('anima-session engine requires a non-empty string "cwd" given.');
31	    }
32	
33	    const animator = guild().apparatus<AnimatorApi>('animator');
34	    const writ = givens.writ as WritDoc | undefined;
35	
36	    const handle = animator.summon({
37	      role: givens.role,
38	      prompt: givens.prompt,
39	      cwd: givens.cwd,
40	      ...(givens.conversationId ? { conversationId: givens.conversationId as string } : {}),
41	      environment: writ ? { GIT_AUTHOR_EMAIL: `${writ.id}@nexus.local` } : {},
42	      metadata: { engineId: context.engineId, ...(writ ? { writId: writ.id } : {}) },
43	      // Enable streaming so the provider generates real-time chunks that the
44	      // Animator's broadcaster captures for subscribeToSession() consumers.
45	      streaming: true,
46	    });
47	
48	    return { status: 'launched', sessionId: handle.sessionId };
49	  },
50	};
51	
52	export default animaSessionEngine;
